// Parse Grafana Alerting webhook payload
const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [body];
const results = [];

for (const alert of alerts) {
  const status = alert.status || body.status || 'firing';
  if (status !== 'firing' && status !== 'resolved') continue;

  const labels = alert.labels || {};
  const annotations = alert.annotations || {};
  const values = alert.values || alert.valueString || '';

  results.push({
    json: {
      alertname: labels.alertname || body.title || 'Unknown Alert',
      severity: labels.severity || 'warning',
      status: status,
      summary: annotations.summary || annotations.description || '',
      values: typeof values === 'object' ? JSON.stringify(values) : String(values),
      dashboardURL: alert.dashboardURL || '',
      panelURL: alert.panelURL || ''
    }
  });
}

return results.length > 0 ? results : [];

// P0 FIX: Rate limiter - max 20 alerts per 5-minute window
const MAX_ALERTS = 20;
const WINDOW_MS = 5 * 60 * 1000;

const now = Date.now();
const staticData = $getWorkflowStaticData('global');

if (!staticData.alertRateLimitEntries) {
  staticData.alertRateLimitEntries = [];
}
staticData.alertRateLimitEntries = staticData.alertRateLimitEntries.filter(ts => now - ts < WINDOW_MS);

const isRateLimited = staticData.alertRateLimitEntries.length >= MAX_ALERTS;

if (!isRateLimited) {
  staticData.alertRateLimitEntries.push(now);
}

return [{
  json: {
    ...$input.first().json,
    isRateLimited,
    rateLimitCount: staticData.alertRateLimitEntries.length,
    rateLimitMax: MAX_ALERTS
  }
}];

// SYNC: This classification logic is duplicated in error-to-github-issue.json
// Auto-classify alert: detect service, host, priority, target repo
const SERVICE_MAP = {
  'mcphub': 'svc:mcphub', 'mcp': 'svc:mcphub',
  'grafana': 'svc:grafana', 'prometheus': 'svc:grafana',
  'elk': 'svc:elk', 'elasticsearch': 'svc:elk', 'logstash': 'svc:elk', 'kibana': 'svc:elk',
  'glitchtip': 'svc:glitchtip',
  'traefik': 'svc:traefik', 'proxy': 'svc:traefik', 'gateway': 'svc:traefik',
  'n8n': 'svc:n8n',
  'blacklist': 'svc:blacklist',
  'proxmox': 'svc:proxmox', 'ceph': 'svc:proxmox', 'pve': 'svc:proxmox'
};
const HOST_MAP = {
  'pve': 'host:pve', 'pve3': 'host:pve',
  'mcphub': 'host:mcphub', 'grafana': 'host:grafana',
  'elk': 'host:elk', 'traefik': 'host:traefik',
  'glitchtip': 'host:glitchtip', 'oc': 'host:oc', 'jclee-dev': 'host:oc',
  'sandbox': 'host:sandbox', 'ubuntu': 'host:sandbox', 'runner': 'host:runner'
};
const SEVERITY_MAP = {
  'critical': 'P0-critical', 'fatal': 'P0-critical',
  'error': 'P1-high', 'warning': 'P2-medium', 'warn': 'P2-medium',
  'info': 'P3-low', 'debug': 'P3-low'
};

const d = $input.first().json;
const searchText = (d.alertname + ' ' + d.summary).toLowerCase();

let serviceLabel = '';
for (const [kw, lbl] of Object.entries(SERVICE_MAP)) {
  if (searchText.includes(kw)) { serviceLabel = lbl; break; }
}
let hostLabel = '';
for (const [kw, lbl] of Object.entries(HOST_MAP)) {
  if (searchText.includes(kw)) { hostLabel = lbl; break; }
}
const priorityLabel = SEVERITY_MAP[d.severity.toLowerCase()] || 'P2-medium';
const targetRepo = serviceLabel === 'svc:blacklist' ? 'qws941/blacklist' : 'qws941/terraform';

const labels = ['infrastructure', 'alert', 'automated', priorityLabel];
if (serviceLabel) labels.push(serviceLabel);
if (hostLabel) labels.push(hostLabel);

return [{ json: { ...d, classifiedLabels: labels, targetRepo } }];

// Check if an open issue already exists for this alertname
const alertname = $('Parse Alert Payload').first().json.alertname;
const prefix = `[Alert] ${alertname}:`;
const issues = $input.first().json.body || $input.first().json;
const issueList = Array.isArray(issues) ? issues : [];

const existing = issueList.find(issue => issue.title && issue.title.startsWith(prefix));

if (existing) {
  return [{ json: { isDuplicate: true, existingIssueNumber: existing.number, alertname } }];
} else {
  return [{ json: { isDuplicate: false, existingIssueNumber: null, alertname } }];
}

